import math
import cv2
import mediapipe as mp
import mouse
import time
import pyautogui


class GestureDetector:
    def __init__(self):
        self.mpHands = mp.solutions.hands
        self.hands = self.mpHands.Hands(
            static_image_mode=False,
            max_num_hands=1,
            min_detection_confidence=0.6,
            min_tracking_confidence=0.6
        )

        self.fingerTipLmNumDef = [4, 8, 12, 16, 20]

        self.xScreenRes = 1920
        self.yScreenRes = 1080

        self.camWidth = 1280
        self.camHeight = 720

        self.last_scroll_time = 0
        self.scroll_delay = 0.25

        self.last_click_time = 0
        self.click_delay = 0.6

        self.last_action_time = 0
        self.action_delay = 1.0


def fingers_up(landmarks, tips):
    fingers = [0]

    for tip_id in range(1, 5):
        tip = tips[tip_id]
        pip = tip - 2

        if landmarks[tip][1] < landmarks[pip][1]:
            fingers.append(1)
        else:
            fingers.append(0)

    return fingers


def can_do_action(detector):
    now = time.time()
    if now - detector.last_action_time > detector.action_delay:
        detector.last_action_time = now
        return True
    return False


def main():
    cap = cv2.VideoCapture(0)
    detector = GestureDetector()

    cap.set(cv2.CAP_PROP_FRAME_WIDTH, detector.camWidth)
    cap.set(cv2.CAP_PROP_FRAME_HEIGHT, detector.camHeight)
    cap.set(cv2.CAP_PROP_FPS, 60)

    while True:
        success, img = cap.read()

        if not success or img is None:
            print("Camera error")
            break

        img = cv2.flip(img, 1)
        img = cv2.convertScaleAbs(img, alpha=1.15, beta=8)

        display_img = cv2.resize(img, (960, 540))

        results = detector.hands.process(cv2.cvtColor(img, cv2.COLOR_BGR2RGB))
        landmarks = []

        if results.multi_hand_landmarks:
            h, w, _ = img.shape

            for handLms in results.multi_hand_landmarks:
                for lm in handLms.landmark:
                    x = int(lm.x * w)
                    y = int(lm.y * h)
                    z = int(lm.z)
                    landmarks.append([x, y, z])

        action_text = "No Hand"

        if landmarks:
            fingers = fingers_up(landmarks, detector.fingerTipLmNumDef)

            index_x, index_y = landmarks[8][0], landmarks[8][1]
            thumb_x, thumb_y = landmarks[4][0], landmarks[4][1]

            screen_x = int(index_x * detector.xScreenRes / detector.camWidth)
            screen_y = int(index_y * detector.yScreenRes / detector.camHeight)

            draw_x = int(index_x * 960 / detector.camWidth)
            draw_y = int(index_y * 540 / detector.camHeight)

            cv2.circle(display_img, (draw_x, draw_y), 10, (0, 0, 255), cv2.FILLED)

            action_text = "No Action"

            # 1) ☝️ صباع واحد = تحريك الماوس
            if fingers == [0, 1, 0, 0, 0]:
                mouse.move(screen_x, screen_y, absolute=True, duration=0.03)
                action_text = "Mouse Move"

            # 2) 🤏 الإبهام قريب من السبابة = Left Click
            distance = math.hypot(index_x - thumb_x, index_y - thumb_y)

            if distance < 45:
                now = time.time()
                if now - detector.last_click_time > detector.click_delay:
                    mouse.click("left")
                    detector.last_click_time = now
                    action_text = "Left Click"
                    print("Left Click")

            # 3) ✌️ صباعين = Scroll Down
            if fingers == [0, 1, 1, 0, 0]:
                now = time.time()
                if now - detector.last_scroll_time > detector.scroll_delay:
                    mouse.wheel(-5)
                    detector.last_scroll_time = now
                    action_text = "Scroll Down"
                    print("Scroll Down")

            # 4) 3 صوابع = Scroll Up
            if fingers == [0, 1, 1, 1, 0]:
                now = time.time()
                if now - detector.last_scroll_time > detector.scroll_delay:
                    mouse.wheel(5)
                    detector.last_scroll_time = now
                    action_text = "Scroll Up"
                    print("Scroll Up")

            # 5) ✋ أربع صوابع مفتوحة = Volume Up
            if fingers == [0, 1, 1, 1, 1]:
                if can_do_action(detector):
                    pyautogui.press("volumeup")
                    action_text = "Volume Up"
                    print("Volume Up")

            # 6) ✊ قبضة = Volume Down
            if fingers == [0, 0, 0, 0, 0]:
                if can_do_action(detector):
                    pyautogui.press("volumedown")
                    action_text = "Volume Down"
                    print("Volume Down")

            cv2.putText(display_img, f"Fingers: {fingers}", (20, 40),
                        cv2.FONT_HERSHEY_SIMPLEX, 0.8, (0, 255, 0), 2)

        cv2.putText(display_img, f"Action: {action_text}", (20, 80),
                    cv2.FONT_HERSHEY_SIMPLEX, 0.8, (255, 255, 0), 2)

        cv2.putText(display_img, "Q = Quit", (20, 520),
                    cv2.FONT_HERSHEY_SIMPLEX, 0.7, (0, 0, 255), 2)

        cv2.imshow("Hand Mouse Control", display_img)

        if cv2.waitKey(1) & 0xFF == ord("q"):
            break

    cap.release()
    cv2.destroyAllWindows()


if __name__ == "__main__":
    main()

